   233→  grpc::health::v1::HealthCheckRequest request;
   234→  if (parent_.service_name_.has_value()) {
   235→    request.set_service(parent_.service_name_.value());
   236→  }
   237→
   238→  request_encoder_->encodeData(*Grpc::Common::serializeToGrpcFrame(request), true);
